{"viz_type": "mermaid_classDiagram", "viz_dsl": "classDiagram
    class HuggingFaceTokenizer {
        +String name
        +Int vocab_size
        +Int model_max_length
        +encode(text: String) List~Int~
        +decode(ids: List~Int~) String
    }
    class TransformerEncoderModel {
        +String checkpoint
        +Int hidden_dim
        +Int num_layers
        +HuggingFaceTokenizer tokenizer
        +forward(input_ids: List~Int~) Tensor
    }
    TransformerEncoderModel *-- HuggingFaceTokenizer : composes"}

{"viz_type": "mermaid_classDiagram", "viz_dsl": "classDiagram
    class GenerativeModel {
        <<interface>>
        +sample(prompt: String) String
        +log_prob(prompt: String, completion: String) Float
    }
    class AutoregressiveDecoder {
        +Int context_window
        +Float temperature
        +sample(prompt: String) String
        +log_prob(prompt: String, completion: String) Float
    }
    class DenseTransformerLM {
        +Int hidden_dim
        +Int num_attention_heads
        +Int num_layers
        +forward(token_ids: Tensor) Tensor
    }
    class MixtureOfExpertsLM {
        +Int hidden_dim
        +Int num_experts
        +Int experts_per_token
        +Float router_z_loss_weight
        +forward(token_ids: Tensor) Tensor
        +route(hidden: Tensor) Tensor
    }
    GenerativeModel <|.. AutoregressiveDecoder : implements
    AutoregressiveDecoder <|-- DenseTransformerLM : extends
    AutoregressiveDecoder <|-- MixtureOfExpertsLM : extends"}

{"viz_type": "mermaid_classDiagram", "viz_dsl": "classDiagram
    class Author {
        +String orcid
        +String full_name
        +String primary_affiliation
    }
    class Publication {
        +String doi
        +String title
        +Int year
        +String venue
    }
    class CitationGraph~T~ {
        +List~T~ nodes
        +List~Tuple~ edges
        +forward_citations(p: T) List~T~
        +backward_citations(p: T) List~T~
    }
    Author "1..*" --> "0..*" Publication : authored
    Publication "0..*" --> "0..*" Publication : cites
    CitationGraph~Publication~ o-- "1..*" Publication : aggregates"}

consolidated.mermaid_classDiagram:
{"viz_type": "mermaid_classDiagram", "viz_dsl": "classDiagram
    class Pipeline {
        <<abstract>>
        +String pipeline_id
        +run(document: Document) PipelineResult
    }
    class DocVizPipeline {
        +String name
        +Int max_visualizations
        +run(document: Document) PipelineResult
    }
    class PipelineStep {
        <<interface>>
        +execute(state: PipelineState) PipelineState
    }
    class CapacityAnalyzer {
        +Int min_chunk_chars
        +execute(state: PipelineState) PipelineState
    }
    class VisualizationClassifier {
        +String model_name
        +Float confidence_threshold
        +execute(state: PipelineState) PipelineState
    }
    class ContentArchitect {
        +String prompt_template
        +execute(state: PipelineState) PipelineState
    }
    class Document {
        +String source_uri
        +List~Chunk~ chunks
    }
    class Chunk {
        +Int chunk_id
        +String text
        +Int char_count
    }
    Pipeline <|-- DocVizPipeline : extends
    PipelineStep <|.. CapacityAnalyzer : implements
    PipelineStep <|.. VisualizationClassifier : implements
    PipelineStep <|.. ContentArchitect : implements
    DocVizPipeline *-- "1..*" PipelineStep : composes
    DocVizPipeline --> "1" Document : processes
    Document *-- "1..*" Chunk : segmented_into"}
